SELECT id, feeder_id AS feederId, feeder_name AS feederName, feeder_role AS feederRole, animal_id AS animalId, animal_name AS animalName, animal_type AS animalType, point_id AS pointId, point_name AS pointName, feeding_time AS feedingTime, food_type AS foodType, food_amount AS foodAmount, status, notes, photos, audit_history AS auditHistory, is_deleted AS isDeleted, create_time AS createTime, update_time AS updateTime FROM feeding_record
is_deleted = 0
AND feeder_id = #{feederId}
AND feeder_name LIKE concat('%', #{feederName}, '%')
AND feeder_role = #{feederRole}
AND animal_id = #{animalId}
AND animal_name LIKE concat('%', #{animalName}, '%')
AND animal_type = #{animalType}
AND point_id = #{pointId}
AND point_name LIKE concat('%', #{pointName}, '%')
AND food_type = #{foodType}
AND status = #{status}
AND feeding_time >= #{startTime}
AND feeding_time <= #{endTime}
ORDER BY feeding_time DESC
LIMIT #{current}, #{size}

